class Solution {
public:
    vector<int> diffWaysToCompute(string expression) {
        unordered_map<string, vector<int>> memo;
        return compute(expression, memo);
    }

    vector<int> compute(const string& expression, unordered_map<string, vector<int>>& memo) {
        if (memo.count(expression)) return memo[expression];

        vector<int> results;
        for (int i = 0; i < expression.size(); ++i) {
            if (expression[i] == '+' || expression[i] == '-' || expression[i] == '*') {
                vector<int> left = compute(expression.substr(0, i), memo);
                vector<int> right = compute(expression.substr(i + 1), memo);
                for (int l : left) {
                    for (int r : right) {
                        switch (expression[i]) {
                            case '+': results.push_back(l + r); break;
                            case '-': results.push_back(l - r); break;
                            case '*': results.push_back(l * r); break;
                        }
                    }
                }
            }
        }

        if (results.empty()) results.push_back(stoi(expression));
        return memo[expression] = results;
    }
};
